static Instruction *foldNestedSelects(SelectInst &OuterSelVal,
                                      InstCombiner::BuilderTy &Builder) {
  // Canonicalize:
  // select c2, (select c1, a, b), (select c1, b, a)
  //   --> select (xor c1, c2), b, a
  // and its swapped outer-arm variant.
  Value *C1, *A, *B;
  auto matchOppositeSelect = [&](Value *V, Value *OppV, bool SwappedOuterArms)
      -> Instruction * {
    if (!match(V, m_Select(m_Value(C1), m_Value(A), m_Value(B))))
      return nullptr;
    if (!match(OppV, m_Select(m_Specific(C1), m_Specific(B), m_Specific(A))))
      return nullptr;

